/**
 * Integration tests for the DuckDB / D1 / SQLite-WASM materialization.
 *
 * Exercises: schema DDL shape, INSERT placeholder parity, row-to-block
 * round-trip via dims_blob, query builder parameter counts, tenant
 * isolation at the SQL layer.
 *
 * No DuckDB connection is required — the module emits SQL + bound
 * parameter arrays that the caller executes. Tests validate the
 * emitted structure.
 */

import { describe, expect, it } from '@a0n/gnosis/test';
import { createRawStream } from '../prismatic-refraction';
import {
  blocksDimsEqual,
  ingestToKnotgraph,
  type IngestContext,
  type TenantId,
} from '../prismatic-refraction-knotgraph';
import {
  blockToRow,
  duckdbIndexDDL,
  duckdbInsertSQL,
  DUCKDB_INSERT_PLACEHOLDERS,
  duckdbSchemaDDL,
  duckdbSelectByEntity,
  duckdbSelectByRegion,
  duckdbSelectByTenant,
  DUCKDB_TABLE_NAME,
  materializeIngest,
  rowBlobToBlock,
  rowToInsertParams,
} from '../prismatic-refraction-duckdb';

// ─── Fixtures ────────────────────────────────────────────────────────

function lcg(seed: number): () => number {
  let s = seed >>> 0;
  return () => {
    s = (Math.imul(s, 1664525) + 1013904223) >>> 0;
    return s;
  };
}

function randomBytes(seed: number, n: number): number[] {
  const rng = lcg(seed);
  const out = new Array<number>(n);
  for (let i = 0; i < n; i++) out[i] = rng() & 0xff;
  return out;
}

const testTenant: TenantId = { hi: 0x1234_5678, lo: 0x9abc_def0 };

function ctxFor(seed: number): IngestContext {
  return {
    tenant: testTenant,
    typeTag: seed * 1_000_037,
    schemaKnotHash: seed * 2_000_011,
    provenanceDid: seed,
    freshnessClock: seed * 100,
  };
}

// ─── Tests ───────────────────────────────────────────────────────────

describe('Prismatic Refraction → DuckDB / D1 / SQLite-WASM', () => {
  describe('Schema DDL', () => {
    it('emits a CREATE TABLE IF NOT EXISTS with the canonical name', () => {
      const ddl = duckdbSchemaDDL();
      expect(ddl).toContain('CREATE TABLE IF NOT EXISTS');
      expect(ddl).toContain(DUCKDB_TABLE_NAME);
      expect(ddl).toContain('dims_blob       BLOB NOT NULL');
    });

    it('has 15 DOUBLE columns + 1 BLOB column (16 total)', () => {
      const ddl = duckdbSchemaDDL();
      const doubleMatches = ddl.match(/DOUBLE NOT NULL/g) ?? [];
      const blobMatches = ddl.match(/BLOB NOT NULL/g) ?? [];
      expect(doubleMatches.length).toBe(15);
      expect(blobMatches.length).toBe(1);
    });

    it('emits three tenant-scoped indexes', () => {
      const idx = duckdbIndexDDL();
      expect(idx.length).toBe(3);
      for (const stmt of idx) {
        expect(stmt).toContain('CREATE INDEX IF NOT EXISTS');
        expect(stmt).toContain('tenant_hi, tenant_lo');
      }
    });
  });

  describe('INSERT statement + parameter binding', () => {
    it('has exactly 16 placeholders', () => {
      const sql = duckdbInsertSQL();
      const placeholders = (sql.match(/\?/g) ?? []).length;
      expect(placeholders).toBe(DUCKDB_INSERT_PLACEHOLDERS);
      expect(placeholders).toBe(16);
    });

    it('columns in DDL match columns in INSERT', () => {
      const insert = duckdbInsertSQL();
      const columns = [
        'tenant_hi', 'tenant_lo', 'region_id', 'type_tag', 'entity_id',
        'schema_knot', 'parent_commit',
        'field_0', 'field_1', 'field_2', 'field_3', 'field_4', 'field_5',
        'provenance_did', 'freshness_clock', 'dims_blob',
      ];
      for (const c of columns) expect(insert).toContain(c);
    });

    it('rowToInsertParams produces exactly 16 positional values', () => {
      const stream = createRawStream(randomBytes(1, 256));
      const { blocks } = ingestToKnotgraph(stream, 4, ctxFor(1));
      for (const b of blocks) {
        const params = rowToInsertParams(blockToRow(b));
        expect(params.length).toBe(16);
        // Positions 0-14 are numbers, position 15 is the Uint8Array blob.
        for (let i = 0; i < 15; i++) {
          expect(typeof params[i]).toBe('number');
        }
        expect(params[15]).toBeInstanceOf(Uint8Array);
      }
    });
  });

  describe('Row round-trip (dims_blob fidelity)', () => {
    it('rowBlobToBlock is the inverse of blockToRow.dimsBlob', () => {
      for (let seed = 1; seed <= 20; seed++) {
        const stream = createRawStream(randomBytes(seed, 512));
        const { blocks } = ingestToKnotgraph(stream, 8, ctxFor(seed));
        for (const b of blocks) {
          const row = blockToRow(b);
          const rebuilt = rowBlobToBlock(row.dimsBlob);
          expect(blocksDimsEqual(b, rebuilt)).toBe(true);
        }
      }
    });

    it('rowBlobToBlock rejects wrongly-sized blobs', () => {
      expect(() => rowBlobToBlock(new Uint8Array(431))).toThrow();
      expect(() => rowBlobToBlock(new Uint8Array(0))).toThrow();
      expect(() => rowBlobToBlock(new Uint8Array(433))).toThrow();
    });

    it('dims_blob is exactly 432 bytes (54 dims × 8 bytes)', () => {
      const stream = createRawStream(randomBytes(7, 1024));
      const { blocks } = ingestToKnotgraph(stream, 8, ctxFor(1));
      for (const b of blocks) {
        const row = blockToRow(b);
        expect(row.dimsBlob.byteLength).toBe(432);
      }
    });
  });

  describe('materializeIngest end-to-end', () => {
    it('bundles DDL + indexes + INSERT sql + one params row per block', () => {
      const stream = createRawStream(randomBytes(1, 2048));
      const result = ingestToKnotgraph(stream, 8, ctxFor(1));
      const mat = materializeIngest(result);
      expect(mat.ddl).toContain('CREATE TABLE');
      expect(mat.indexes.length).toBe(3);
      expect(mat.insertSql).toContain('INSERT INTO');
      expect(mat.params.length).toBe(result.blocks.length);
      for (const p of mat.params) {
        expect(p.length).toBe(16);
      }
    });

    it('is deterministic across independent pipelines', () => {
      for (let seed = 1; seed <= 10; seed++) {
        const stream = createRawStream(randomBytes(seed, 1024));
        const a = materializeIngest(ingestToKnotgraph(stream, 8, ctxFor(seed)));
        const b = materializeIngest(ingestToKnotgraph(stream, 8, ctxFor(seed)));
        expect(a.params.length).toBe(b.params.length);
        for (let i = 0; i < a.params.length; i++) {
          for (let j = 0; j < 15; j++) {
            expect(a.params[i]![j]).toBe(b.params[i]![j]);
          }
          const blobA = a.params[i]![15] as Uint8Array;
          const blobB = b.params[i]![15] as Uint8Array;
          expect(blobA.byteLength).toBe(blobB.byteLength);
          for (let k = 0; k < blobA.byteLength; k++) {
            expect(blobA[k]).toBe(blobB[k]);
          }
        }
      }
    });
  });

  describe('Query builders (tenant isolation at the SQL layer)', () => {
    it('duckdbSelectByTenant binds (hi, lo)', () => {
      const q = duckdbSelectByTenant(testTenant);
      expect(q.params).toEqual([testTenant.hi, testTenant.lo]);
      expect(q.sql).toContain('tenant_hi = ? AND tenant_lo = ?');
      expect(q.sql).toContain(DUCKDB_TABLE_NAME);
    });

    it('duckdbSelectByRegion binds (hi, lo, regionId)', () => {
      const q = duckdbSelectByRegion(testTenant, 7);
      expect(q.params).toEqual([testTenant.hi, testTenant.lo, 7]);
      expect(q.sql).toContain('tenant_hi = ? AND tenant_lo = ? AND region_id = ?');
    });

    it('duckdbSelectByEntity binds (hi, lo, entityId)', () => {
      const q = duckdbSelectByEntity(testTenant, 0xabcdef);
      expect(q.params).toEqual([testTenant.hi, testTenant.lo, 0xabcdef]);
      expect(q.sql).toContain('tenant_hi = ? AND tenant_lo = ? AND entity_id = ?');
    });

    it('every query builder filters by tenant (no cross-tenant reads)', () => {
      const queries = [
        duckdbSelectByTenant(testTenant),
        duckdbSelectByRegion(testTenant, 3),
        duckdbSelectByEntity(testTenant, 1),
      ];
      for (const q of queries) {
        expect(q.sql).toContain('tenant_hi = ?');
        expect(q.sql).toContain('tenant_lo = ?');
      }
    });
  });

  describe('End-to-end simulation (in-memory roundtrip)', () => {
    it('materialize → simulated SELECT by tenant → rebuild blocks', () => {
      // Simulate a DB by executing INSERTs into a local Map keyed by
      // (tenant_hi, tenant_lo, entity_id), then "query by tenant" is a
      // filter over that map.
      const stream = createRawStream(randomBytes(3, 4096));
      const ctx = ctxFor(3);
      const result = ingestToKnotgraph(stream, 8, ctx);
      const mat = materializeIngest(result);

      // Simulated table row store.
      interface StoredRow {
        tenant_hi: number;
        tenant_lo: number;
        region_id: number;
        entity_id: number;
        dims_blob: Uint8Array;
      }
      const table: StoredRow[] = [];
      for (const params of mat.params) {
        table.push({
          tenant_hi: params[0] as number,
          tenant_lo: params[1] as number,
          region_id: params[2] as number,
          entity_id: params[4] as number,
          dims_blob: params[15] as Uint8Array,
        });
      }

      // "SELECT by tenant" — all rows should match (all produced with
      // testTenant).
      const byTenant = table.filter(
        (r) => r.tenant_hi === testTenant.hi && r.tenant_lo === testTenant.lo,
      );
      expect(byTenant.length).toBe(result.blocks.length);

      // Rebuild every stored row back into a KnotgraphShapedBlock and
      // verify bit-equal to the original.
      for (let i = 0; i < result.blocks.length; i++) {
        const rebuilt = rowBlobToBlock(byTenant[i]!.dims_blob);
        expect(blocksDimsEqual(result.blocks[i]!, rebuilt)).toBe(true);
      }

      // "SELECT by tenant" for a different tenant returns zero rows.
      const otherTenant: TenantId = { hi: 0xdead_beef, lo: 0xcafe_babe };
      const byOther = table.filter(
        (r) => r.tenant_hi === otherTenant.hi && r.tenant_lo === otherTenant.lo,
      );
      expect(byOther.length).toBe(0);
    });
  });
});
